import { AfterViewInit, Component, Input, OnInit, ViewChild } from '@angular/core';
import { MatTableDataSource } from '@angular/material/table';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { MatDialog } from '@angular/material/dialog';
import { TableColumn } from '../../../../ux/interfaces/table-column.interface';
import { SelectionModel } from '@angular/cdk/collections';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { stagger40ms } from '../../../../ux/animations/stagger.animation';
import { UntypedFormControl } from '@angular/forms';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';
import { SharedService } from 'src/app/shared/shared.service';
import { TicketticketsalesreportService } from './ticketsalesreport.service';
import { UnitmasterService } from '../../setup/unitmaster/unitmaster.service';
import { MatSnackBar } from '@angular/material/snack-bar';

@UntilDestroy()
@Component({
  selector: 'ux-ticketsalesreport',
  templateUrl: './ticketsalesreport.component.html',
  styleUrls: ['./ticketsalesreport.component.scss']
})
export class TicketsalesreportComponent implements OnInit {
  from_date = '';
  to_date = '';
  unit_id = '';
  sales_orders_list = [];

  unit_subscription: Subscription;
  units_list = [];

  constructor(
    private ticketsalesService: TicketticketsalesreportService,
    private _snackBar: MatSnackBar,
    private unitService: UnitmasterService,
    private dialog: MatDialog
  ) {

  }

  ngOnInit(): void {

    this.unitService.getAllUnitmaster().subscribe();

    this.unit_subscription = this.unitService.unitmasterChanged
      .subscribe(
        (units: any[]) => {
          this.units_list = units;
          console.log(this.units_list)
        }
      );
  }

  onUnitChange(event: any) {
    console.log(event.value);
  }

  filtered_total = 0;
  searched = false;
  async onSearchClick() {
    if (this.from_date && this.to_date) {
      this.sales_orders_list = [];
      this.filtered_total = 0;
      this.searched = true;
      let reportData = {
        fromdate: this.from_date,
        todate: this.to_date,
        unit_id: this.unit_id
      }
      console.log(reportData);
      this.ticketsalesService.getSalesReport(reportData)
        .then((res: any) => {
          console.log(res);
          this.sales_orders_list = res.filteredorders || [];

          this.sales_orders_list.forEach(element => {
            this.filtered_total += Number(element.total_amount);
          });

        })
        .catch((err: any) => {

        })
    } else {
      this.openSnackBar('Information', 'Select From Date and To Date')
    }
  }

  openSnackBar(title: string, message: string) {
    this._snackBar.open(message, title, {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'bottom',
    });
  }
}
