import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { map, tap } from 'rxjs/operators';
import { Subject } from 'rxjs';
import { apiKey, baseUrl } from 'src/environments/environment';

@Injectable({ providedIn: 'root' })
export class TicketticketsalesreportService {
    private groups: any[] = [];
    groupsChanged = new Subject<any[]>();

    constructor(
        private http: HttpClient,
        private router: Router
    ) { }

    async getSalesReport(reportData: any) {
        return new Promise((resolve, reject) => {
            this.http.post(
                baseUrl + '/api/postransactions/getordersbetweendates/',
                JSON.stringify(reportData),
                {
                    headers: new HttpHeaders()
                        .set('Content-Type', 'application/json')
                })
                .subscribe(res => {
                    resolve(res);
                }, (err) => {
                    reject(err);
                });
        });
    }
}